return await space.current.patchWidget("snake-game", {
  edits: [
    {
      op: "replace",
      path: "/renderer",
      value: async (parent) => {
        const root = document.createElement("div")
        root.style.cssText = "position:relative;width:100%;height:100%;overflow:hidden;background:#0b1020;border-radius:12px;"
        root.innerHTML = `
          <style>
            .snake-canvas{width:100%;height:100%;display:block}
          </style>
          <canvas class="snake-canvas"></canvas>
        `
        parent.innerHTML = ""
        parent.appendChild(root)

        const canvas = root.querySelector("canvas")
        const ctx = canvas.getContext("2d")

        const resize = () => {
          const r = root.getBoundingClientRect()
          canvas.width = Math.max(1, Math.floor(r.width * devicePixelRatio))
          canvas.height = Math.max(1, Math.floor(r.height * devicePixelRatio))
          canvas.style.width = r.width + "px"
          canvas.style.height = r.height + "px"
        }
        resize()
        new ResizeObserver(resize).observe(root)

        const state = {
          head: { x: 0.5, y: 0.5 },
          dir: { x: 1, y: 0 },
          segments: Array.from({ length: 18 }, (_, i) => ({ x: 0.5 - i * 0.025, y: 0.5 })),
          t: 0
        }

        const draw = () => {
          state.t += 0.02
          const w = canvas.width, h = canvas.height
          ctx.clearRect(0, 0, w, h)

          const step = 0.004
          state.head.x += state.dir.x * step
          state.head.y += state.dir.y * step
          if (state.head.x > 0.92 || state.head.x < 0.08) state.dir.x *= -1
          if (state.head.y > 0.92 || state.head.y < 0.08) state.dir.y *= -1
          state.head.x = Math.max(0.08, Math.min(0.92, state.head.x))
          state.head.y = Math.max(0.08, Math.min(0.92, state.head.y))

          state.segments.unshift({ x: state.head.x, y: state.head.y })
          state.segments.length = 18

          const maxRadius = Math.min(w, h) * 0.045
          const minRadius = maxRadius * 0.6

          for (let i = state.segments.length - 1; i >= 0; i--) {
            const s = state.segments[i]
            const age = i / (state.segments.length - 1)
            const radius = maxRadius * (1 - age) + minRadius * age
            const x = s.x * w
            const y = s.y * h

            ctx.beginPath()
            ctx.fillStyle = `hsl(${140 + age * 40}, 80%, ${55 - age * 10}%)`
            ctx.arc(x, y, radius, 0, Math.PI * 2)
            ctx.fill()
          }

          requestAnimationFrame(draw)
        }
        draw()
      }
    }
  ]
})

