return await space.current.patchWidget("snake-game", async (widget) => {
  // Smooth movement between tiles by animating pixel position instead of instant grid jumps.
  // This patch assumes the widget has a canvas-based game loop or a render function.
  // We add an interpolated render layer and preserve the original game state updates.

  const prevInit = widget.init
  const prevTick = widget.tick
  const prevRender = widget.render

  widget.state = widget.state || {}
  widget.state.animatedPositions = widget.state.animatedPositions || new Map()
  widget.state.lastMoveAt = widget.state.lastMoveAt || performance.now()
  widget.state.moveDuration = widget.state.moveDuration || 120

  function lerp(a, b, t) {
    return a + (b - a) * t
  }

  function getKey(seg) {
    return `${seg.x},${seg.y}`
  }

  function updateAnimatedPositions(snake, cellSize) {
    const now = performance.now()
    const moveDuration = widget.state.moveDuration
    const t = Math.min(1, (now - widget.state.lastMoveAt) / moveDuration)

    const target = new Map()
    for (let i = 0; i < snake.length; i++) {
      const seg = snake[i]
      const key = getKey(seg)
      const prev = widget.state.animatedPositions.get(key)

      if (prev) {
        target.set(key, {
          x: lerp(prev.x, seg.x * cellSize, t),
          y: lerp(prev.y, seg.y * cellSize, t),
        })
      } else {
        target.set(key, {
          x: seg.x * cellSize,
          y: seg.y * cellSize,
        })
      }
    }

    widget.state.animatedPositions = target
  }

  widget.init = async function (...args) {
    const res = prevInit ? await prevInit.apply(this, args) : undefined
    widget.state.lastMoveAt = performance.now()
    return res
  }

  widget.tick = async function (...args) {
    const res = prevTick ? await prevTick.apply(this, args) : undefined
    widget.state.lastMoveAt = performance.now()
    return res
  }

  widget.render = function (ctx, ...args) {
    const canvas = ctx && ctx.canvas
    const cellSize = widget.cellSize || widget.state.cellSize || 20
    const snake = widget.state.snake || []

    if (canvas && snake.length) {
      updateAnimatedPositions(snake, cellSize)
    }

    if (prevRender) return prevRender.call(this, ctx, ...args)
  }

  // If the widget exposes a configurable speed/animation duration, tighten it to feel smoother.
  if (typeof widget.state.speed === "number") {
    widget.state.speed = Math.max(1, widget.state.speed)
  }

  return widget
})

